### 1 Edge Reference Syntax

```jac
node Person {}
edge EdgeType {}
edge Edge { has attr: int = 0; has a: int = 0; has b: int = 0; }
edge Friend {}

walker Traverser {
    can query with Person entry {
        # Basic forms
        outgoing = [-->];                     # All outgoing nodes
        incoming = [<--];                     # All incoming nodes
        both = [<-->];                        # Both directions

        # Typed forms
        via_type = [->:EdgeType:->];          # Outgoing via EdgeType

        # With conditions
        filtered = [->:Edge:attr > 0:->];     # Filter by edge attribute

        # Node type filter
        people = [-->][?:Person];             # Filter result nodes by type

        # Get edges vs nodes
        edges = [edge -->];                   # Get edge objects
        friends = [edge ->:Friend:->];        # Typed edge objects
    }
}
```

```jac
# Before: Exit ability would run before disengage stops traversal
walker MyWalker {
    can process with MyNode entry {
        if some_condition { disengage; }
        visit [-->];
    }
    can cleanup with Root exit {
        # This WOULD run before disengage in old semantics
        print("Cleanup");
    }
}

# After: Use entry ability instead, since exits won't run after disengage
walker MyWalker {
    can process with MyNode entry {
        if some_condition { disengage; }
        visit [-->];
    }
    can cleanup with Root entry {
        # Use entry to ensure this runs before any disengage
        print("Cleanup will run");
    }
}
```
